                &lt;/a&gt;
            &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class="w-full md:w-1/2 flex justify-center md:justify-end"&gt;
            &lt;img src="https://picsum.photos/seed/faculty/600/400" alt="学院教师团队合影" class="rounded-lg shadow-2xl max-w-full h-auto object-cover transform hover:scale-105 transition-transform duration-500"&gt;
        &lt;/div&gt;
